VALUES ('d1713a35-1922-4190-a658-24d9fc8019f5', 'Which value of $x$ satisfies $5x + 4 > 77$?', NULL, NULL, '[{"id":"A","text":"$13$","is_correct":false,"explanation":"Substituting gives 5(13)+4=69, not greater than 77."},{"id":"B","text":"$14$","is_correct":false,"explanation":"Substituting gives 5(14)+4=74, not greater than 77."},{"id":"C","text":"$15$","is_correct":true,"explanation":"Substituting gives 5(15)+4=79 > 77."},{"id":"D","text":"$16$","is_correct":false,"explanation":"Greater than needed; C is the smallest valid choice."}]'::jsonb, 'C', 'Solve: $5x > 73$, so $x > 14.6$. The smallest listed value is $15$.', NULL, 'Algebra', 'Linear inequalities', 'math', 'algebra', 'INE', 'INE', 'medium', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('82a1758a-bbc7-4a29-a4d3-f1b96517fe0d', 'Which expression is equivalent to $(4x + 8)(4x - 8)$?', NULL, NULL, '[{"id":"A","text":"$4x^2 - 8$","is_correct":false,"explanation":"Incorrect square of the first term."},{"id":"B","text":"$16x^2 - 64$","is_correct":true,"explanation":"Difference of squares: $(4x)^2 - (8)^2 = 16x^2 - 64$."},{"id":"C","text":"$8x - 16$","is_correct":false,"explanation":"This expands to a linear expression, not the quadratic."},{"id":"D","text":"$12x^2$","is_correct":false,"explanation":"Does not follow the product pattern."}]'::jsonb, 'B', 'Use difference of squares: $(4x + 8)(4x - 8) = 16x^2 - 64$.', NULL, 'Advanced Math', 'Equivalent expressions', 'math', 'advanced', 'EQS', 'EQS', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
