VALUES ('a9e0582e-0f47-44fd-b1ae-951dd892da1c', 'Which expression is equivalent to $(2x + 12)(2x - 12)$?', NULL, NULL, '[{"id":"A","text":"$2x^2 - 12$","is_correct":false,"explanation":"Incorrect square of the first term."},{"id":"B","text":"$4x^2 - 144$","is_correct":true,"explanation":"Difference of squares: $(2x)^2 - (12)^2 = 4x^2 - 144$."},{"id":"C","text":"$4x - 24$","is_correct":false,"explanation":"This expands to a linear expression, not the quadratic."},{"id":"D","text":"$14x^2$","is_correct":false,"explanation":"Does not follow the product pattern."}]'::jsonb, 'B', 'Use difference of squares: $(2x + 12)(2x - 12) = 4x^2 - 144$.', NULL, 'Advanced Math', 'Equivalent expressions', 'math', 'advanced', 'EQS', 'EQS', 'medium', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
