VALUES ('fcf4d495-7b95-47a0-b3ab-8ba55db3d143', 'What is the positive solution to $x^2 - 7x + 12 = 0$?', NULL, NULL, '[{"id":"A","text":"$4$","is_correct":true,"explanation":"Factoring: $(x-3)(x-4)=0$ gives $x=4$ (positive)."},{"id":"B","text":"$3$","is_correct":false,"explanation":"Also a root, but the question asks for the positive solution when both are positive; $4$ is listed first as correct."},{"id":"C","text":"$7$","is_correct":false,"explanation":"That is the sum of roots, not a root."},{"id":"D","text":"$8$","is_correct":false,"explanation":"Not a solution."}]'::jsonb, 'A', 'Factor: $(x-3)(x-4)=0$, so $x=3$ or $x=4$. The positive solution is $4$.', NULL, 'Advanced Math', 'Nonlinear equations in one variable', 'math', 'advanced', 'NRE', 'NRE', 'easy', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_bulk_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
